AND AA.RSK_NO = #{RSK_NO,jdbcType=VARCHAR}
AND AA.RSK_NM LIKE '%' || #{RSK_NM,jdbcType=VARCHAR} || '%'
AND AA.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND AA.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND AA.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
) CC
WHERE CC.REG_YN = #{REG_YN,jdbcType=VARCHAR}

SELECT * FROM ( SELECT AA.RSK_NO, AA.RSK_NM, AA.RSK_G_C, AA.RSK_FLD_C, AA.RSK_BUMUN_C ,GET_RBA_RSK_NAME('RSK_G', AA.RSK_G_C) AS RSK_G_C_NM ,GET_RBA_RSK_NAME('RSK_F', AA.RSK_FLD_C) AS RSK_FLD_C_NM ,GET_RBA_RSK_NAME('RSK_B', AA.RSK_BUMUN_C) AS RSK_BUMUN_C_NM ,DECODE(BB.RSK_NO,NULL,'N','Y') AS REG_YN ,NVL(BB.TONGJE_GD_RT,'50') AS TONGJE_GD_RT ,NVL(BB.KCI_GD_RT,'50') AS KCI_GD_RT FROM RBA_RSK_M AA LEFT OUTER JOIN (SELECT A.RSK_NO ,NVL(MAX(TONGJE_GD_RT),'50') AS TONGJE_GD_RT ,NVL(MAX(KCI_GD_RT),'50') AS KCI_GD_RT FROM RBA_TONGJE_RT_M A, RBA_TONGJE_RT_S B WHERE A.RSK_NO != 'RK0000000000' AND A.RSK_NO = B.RSK_NO AND A.LST_SER = B.TONGJE_RT_SER GROUP BY A.RSK_NO) BB ON AA.RSK_NO = BB.RSK_NO WHERE AA.USYN = 1 AND AA.RSK_B_C = 'T'
AND AA.RSK_NO = #{RSK_NO,jdbcType=VARCHAR}
AND AA.RSK_NM LIKE '%' || #{RSK_NM,jdbcType=VARCHAR} || '%'
AND AA.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND AA.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND AA.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
) CC
WHERE CC.REG_YN = #{REG_YN,jdbcType=VARCHAR}

