SELECT (SELECT RBA_RSK_C_NM AS CD_NM FROM RBA_RSK_C_M WHERE USYN=1 AND RBA_RSK_C = 'RSK_G' and RBA_RSK_C_V = A.RSK_G_C ) AS RSK_GUBUN_NM, A.RSK_G_C AS RSK_GUBUN, (SELECT RBA_RSK_C_NM AS CD_NM FROM RBA_RSK_C_M WHERE USYN=1 AND RBA_RSK_C = 'RSK_F' and RBA_RSK_C_V = A.RSK_FLD_C ) AS RSK_FLD_NM, A.RSK_FLD_C AS RSK_FLD, (SELECT RBA_RSK_C_NM AS CD_NM FROM RBA_RSK_C_M WHERE USYN=1 AND RBA_RSK_C = 'RSK_B' and RBA_RSK_C_V = A.RSK_BUMUN_C ) AS RSK_BUMUN_NM, A.RSK_BUMUN_C AS RSK_BUMUN, A.KRI_NM AS KRI_NM, B.KRI_V AS KRI_V, GET_CODE_NAME ('R011', A.UNIT_C) AS UNIT_NM, A.UNIT_C AS UNIT, A.KRI_CTNT AS CTNT, B.KRI_CALC_HIS AS CALC_HIS, CASE WHEN A.USYN='1' THEN 'Y' ELSE 'N' END AS USYN_NM, A.USYN AS USYN, GET_CODE_NAME ('R012', A.RESC_G_C) AS RESC_G_C_NM, A.RESC_G_C AS RESC_G_C, A.KRI_NO AS KRI_NO, A.DR_OP_JKW_NO AS DR_OP_JKW_NO FROM RBA_KRI_M A, RBA_IKRI_S B WHERE A.KRI_NO = B.KRI_NO(+) AND A.DR_DT = B.DR_DT(+) AND RSK_B_C = #{RSK_B_C,jdbcType=VARCHAR}
AND A.RSK_G_C=#{RSKGUBUN,jdbcType=VARCHAR}
AND A.RSK_FLD_C=#{RSKFLD,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C=#{RSKBUMUN,jdbcType=VARCHAR}
AND A.KRI_NO like '%'||#{KRI_NO,jdbcType=VARCHAR}||'%'
AND A.DR_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
ORDER BY A.KRI_NO ASC

SELECT RBA_RSK_C_V AS CD, RBA_RSK_C_NM AS CD_NM, RBA_RSK_C AS GRP_CD FROM RBA_RSK_C_M WHERE USYN=1
AND RBA_RSK_C = #{RBA_RSK_C,jdbcType=VARCHAR}
AND RBA_RSK_C = #{RBA_RSK_C,jdbcType=VARCHAR} AND LENGTH(RBA_RSK_C_V) = 1
AND RBA_RSK_C = #{RBA_RSK_C,jdbcType=VARCHAR} AND LENGTH(RBA_RSK_C_V) = 1
AND RBA_RSK_C = #{RBA_RSK_C,jdbcType=VARCHAR} AND LENGTH(RBA_RSK_C_V) = 1
AND RBA_RSK_C = #{RBA_RSK_C,jdbcType=VARCHAR} AND LENGTH(RBA_RSK_C_V) = 1
AND HRNK_RBA_RSK_C = #{HRNK_RBA_RSK_C,jdbcType=VARCHAR}
AND HRNK_RBA_RSK_C_V = #{HRNK_RBA_RSK_C_V,jdbcType=VARCHAR}
ORDER BY SNO

