AND F.TONGJE_FLD_C = #{TONGJE_F,jdbcType=VARCHAR}
AND F.TONGJE_BUMUN_C = #{TONGJE_B,jdbcType=VARCHAR}
AND DECODE(A.VALT_JINHG_S_C, 0, 1, A.VALT_JINHG_S_C) = #{VALT_JINHG_S_C,jdbcType=VARCHAR}
AND (A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR} OR A.MNGR_JKW_NO=#{JKW_NO,jdbcType=VARCHAR})
AND A.MNGR_JKW_NO = #{MNGR_JKW_NO,jdbcType=VARCHAR}

