AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{MNGR_JKW_NO,jdbcType=VARCHAR}

SELECT A.RSK_NM , (SELECT CD_NM FROM NIC92B WHERE CD = 'R008' AND CNTNT = DECODE(NVL(B.VALT_JINHG_S_C, A.VALT_JINHG_S_C),NULL,1,0,1, NVL(B.VALT_JINHG_S_C, A.VALT_JINHG_S_C)) ) AS VALT_JINHG_S_NM , B.VALT_DT , A.RSK_NO , A.RSK_G_C, GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_G_C_NM , A.RSK_FLD_C, GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD_C_NM , A.RSK_BUMUN_C, GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN_C_NM , G.RSK_PROC_NM , G.SUB_PROC_NM , CASE WHEN TO_CHAR(SYSDATE,'YYYYMMDD') BETWEEN E.VALT_SDT AND E.VALT_EDT THEN 1 ELSE 0 END AS VALT_TERM_YN , DECODE(A.VALT_JINHG_S_C,4,0,8,0,1) AS VALT_POSS_YN , A.LST_VALT_TRN , A.LST_VALT_SER , A.VALT_JINHG_S_C , A.GYLJ_S_C FROM RBA_RSK_M A LEFT JOIN RBA_TRSK_VALT_I B ON A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER AND B.MNG_BRNO = '030' CROSS JOIN (SELECT VALT_SDT, VALT_EDT FROM RBA_RSK_VALT_SCHD WHERE VALT_TRN = (SELECT MAX(VALT_TRN) FROM RBA_RSK_VALT_SCHD WHERE VALT_G = 1 AND VALT_JUNGJI_YN = 0) )E JOIN RBA_PROC_M G ON A.RSK_PROC_NO = G.RSK_PROC_NO WHERE A.RSK_B_C = 'T' AND A.USYN = 1 AND A.GYLJ_S_C = 1
AND A.RSK_G_C = #{RSK_G,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_F,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_B,jdbcType=VARCHAR}
AND A.VALT_JINHG_S_C = #{VALT_JINHG_S_C,jdbcType=VARCHAR}

SELECT ( SELECT MAX(VALT_SER) +1 
         FROM RBA_IRSK_VALT_I 
         WHERE RSK_NO = #{RSK_NO,jdbcType=VARCHAR} 
         AND VALT_TRN = #{VALT_TRN,jdbcType=VARCHAR} 
       ) AS VALT_SER 
FROM DUAL

SELECT NVL(( SELECT MAX(VALT_SER) 
             FROM RBA_IRSK_VALT_I 
             WHERE RSK_NO = #{RSK_NO,jdbcType=VARCHAR} 
             AND VALT_TRN = #{VALT_TRN,jdbcType=VARCHAR} 
           ), 1) AS VALT_SER 
FROM DUAL

SELECT KRI_NO 
FROM RBA_RSK_KRI_MP 
WHERE RSK_NO = #{RSK_NO,jdbcType=VARCHAR}

SELECT KCI_NO 
FROM RBA_RSK_KCI_MP 
WHERE RSK_NO = #{RSK_NO,jdbcType=VARCHAR}

    SELECT COUNT(*) AS CNT 
	FROM RBA_IRSK_KRI_VALT_D 
	WHERE RSK_NO = #{RSK_NO,jdbcType=VARCHAR}
	AND VALT_TRN = #{VALT_TRN,jdbcType=VARCHAR} 
