SELECT A.MNG_BRNO AS MNG_BRNO, (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS JUM_NM, GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_GUBUN, GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD, GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN, A.MNGR_JKW_NO, GET_LOGINID_NAME(MNGR_JKW_NO) AS MNGR_JKW_NM, A.RSK_G_C AS RSK_G_C, RSK_CAUSE_C, GET_CODE_NAME ('R028',A.RSK_CAUSE_C) AS RSK_CAUSE_NM, A.RSK_FLD_C AS RSK_F_C, A.RSK_BUMUN_C AS RSK_B_C, A.RSK_NM AS RSK_NM, A.GYLJ_JKW_NO AS JKW_NO, A.GYLJ_S_C AS AP_YN, A.DR_DT AS DRDT, A.RSK_CTNT AS RSK_CTNT, A.RSK_NO as RSK_NO, A.ATTCH_FILE_NO AS ATTCH_FILE_NO, A.REL_DATA_CTNT AS REL_DATA_CTNT, A.USYN AS USYN, A.VALT_JINHG_S_C AS VALT_JINHG_S_C, A.IMPRV_JINHG_S_C AS IMPRV_JINHG_S_C, E.RSK_PROC_NO AS PROC_NO, E.RSK_PROC_NM AS RSK_PROC_NM, E.SUB_PROC_NM AS SUB_PROC_NM, GET_RBA_RSK_NAME('TONGJE_G', D.TONGJE_G_C) AS TONGJE_G, GET_RBA_RSK_NAME('TONGJE_F', D.TONGJE_FLD_C) AS TONGJE_F, GET_RBA_RSK_NAME('TONGJE_B', D.TONGJE_BUMUN_C) AS TONGJE_B, D.TONGJE_G_C AS TONGJE_G_C, D.TONGJE_FLD_C AS TONGJE_F_C, D.TONGJE_BUMUN_C AS TONGJE_B_C, D.TONGJE_NO AS TONGJE_NO, D.TONGJE_NM AS TONGJE_NM, D.TONGJE_BASE_CTNT AS TONGJE_BASE_CTNT, D.TONGJE_BASE_CTNT1 AS TONGJE_BASE_CTNT1 FROM RBA_RSK_M A, RBA_RSK_TONGJE_MP B, RBA_TONGJE_M D, RBA_PROC_M E WHERE A.RSK_NO=B.RSK_NO(+) AND B.TONGJE_NO = D.TONGJE_NO(+) AND D.RSK_PROC_NO = E.RSK_PROC_NO(+) AND A.RSK_B_C = 'I'
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND D.TONGJE_G_C = #{TONGJE_G_C,jdbcType=VARCHAR}
AND D.TONGJE_FLD_C = #{TONGJE_FLD_C,jdbcType=VARCHAR}
AND D.TONGJE_BUMUN_C = #{TONGJE_BUMUN_C,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{DEP_ID,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
AND A.GYLJ_S_C=#{APP_YN,jdbcType=VARCHAR}
AND A.USYN=#{USYN,jdbcType=VARCHAR}
ORDER BY A.RSK_G_C

