SELECT D.TONGJE_NM AS TONGJE_NM, B.MOFC_TONGJE_GD AS MOFC_TONGJE_GD, /*본부통제등급*/ TO_CHAR(TO_DATE(C.VALT_SDT,'YYYYMMDD'),'YYYY-MM-DD')||'~'||TO_CHAR(TO_DATE(C.VALT_EDT,'YYYYMMDD'),'YYYY-MM-DD') AS VALT_STT_END_DT, /*평가기간*/ (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = B.MNG_BRNO) AS HNG_BR_SWD_NM, /*부서명*/ A.RSK_NM AS RSK_NM, A.IMPRV_JINHG_S_C AS IMPRV_JINHG_S_C, B.REMDR_RSK_GD AS REMDR_RSK_GD, /*잔여위험등급*/ B.GYLJ_DT AS GYLJ_DT,/*개선대상선정일자*/ NVL((SELECT CD_NM FROM NIC92B WHERE CD ='R016' AND CNTNT = S2.IMPRV_PROC_APRV_S_C),'미진행') AS IMPRV_PROC_APRV_S_C, S2.IMPRV_PROC_APRV_S_C as PROC_APRV_S_CODE, CASE WHEN TO_CHAR(S2.IMPRV_VALT_JONGHAP_GD) IS NULL THEN '미결정' ELSE TO_CHAR(S2.IMPRV_VALT_JONGHAP_GD)||'등급' END AS IMPRV_GD, /*개선역량평가*/ S1.IMPRV_V_C AS IMPRV_B_C, /*개선분류CODE*/ (SELECT CD_NM FROM NIC92B WHERE CD ='R021' AND CNTNT = S1.IMPRV_V_C) AS IMPRV_B, S1.IMPRV_G_C AS IMPRV_G_C, /*개선구분CODE*/ (SELECT CD_NM FROM NIC92B WHERE CD ='R022' AND CNTNT = S1.IMPRV_G_C) AS IMPRV_G, GET_LOGINID_NAME(A.MNGR_JKW_NO) AS JKW_NM, /*직원명*/ B.INDV_RSK_GD AS INDV_RSK_GD,/*개별위험등급*/ B.RSK_NO AS RSK_NO, B.VALT_SER AS VALT_SER, /*평가일련번호*/ B.VALT_TRN AS VALT_TRN, /*평가회차*/ B.TONGJE_NO AS TONGJE_NO, S2.CHG_DT AS CHG_DRDT, S2.CHG_TIME AS CHG_DR_TIME, S2.CHG_OP_JKW_NO AS CHG_OP_JKW_NO, B.MNG_BRNO AS MNG_BRNO, /*점번호*/ S2.ATTCH_FILE_NO FROM RBA_RSK_M A LEFT JOIN RBA_TJ_IMPRV_P_D S1 /*통제_개선_처리현황_상세*/ ON A.RSK_NO = S1.RSK_NO AND A.LST_VALT_TRN = S1.VALT_TRN AND A.LST_VALT_SER = S1.VALT_SER AND S1.IMPRV_PROC_HMK_C = 1 LEFT JOIN RBA_TJ_IMPRV_V_I S2 ON A.RSK_NO = S2.RSK_NO AND A.LST_VALT_TRN = S2.VALT_TRN AND A.LST_VALT_SER = S2.VALT_SER ,RBA_IRSK_VALT_I B /*개별위험_평가_내역*/ ,RBA_RSK_VALT_SCHD C /*위험_평가일정*/ ,RBA_TONGJE_M D /*통제_기본*/ WHERE D.TONGJE_NO = B.TONGJE_NO AND A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER AND B.VALT_TRN = C.VALT_TRN AND B.IMPRV_K_C >0 /*전체*/ AND B.VALT_JINHG_S_C = 9
AND B.GYLJ_DT IS NOT NULL AND A.USYN = 1 AND A.RSK_B_C ='I'
AND (B.MNG_BRNO =#{DEP_ID,jdbcType=VARCHAR} OR A.MNGR_JKW_NO=#{JKW_NO,jdbcType=VARCHAR})
AND B.GYLJ_DT BETWEEN #{GYLJ_DT1,jdbcType=VARCHAR} AND #{GYLJ_DT2,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
/*담당자*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (0,1,3,5,#{CHECK_CCD,jdbcType=VARCHAR})
/*승인자*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (2,4,6,#{CHECK_CCD,jdbcType=VARCHAR})
/*전체*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (0,1,2,4,5,6,7,#{CHECK_CCD,jdbcType=VARCHAR})
AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END = #{IMPRV_PROC_APRV_S_C,jdbcType=VARCHAR}
ORDER BY B.MNG_BRNO ASC, CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END ASC, B.VALT_TRN ASC, B.VALT_SER ASC, B.RSK_NO ASC

