SELECT C.RSK_NM AS RSK_NM /*위험명*/ ,TO_CHAR(F.VALT_GD)||'등급' AS KCI_AVG_GD /*KCI평균등급*/ ,E.KCI_NM /*KCI명*/ ,A.VALT_GD /*KCI등급*/ ,B.VALT_DT /*개선대상선정일*/ ,NVL((SELECT CD_NM FROM NIC92B WHERE CD ='R016' AND CNTNT = S2.IMPRV_PROC_APRV_S_C),'미진행') AS IMPRV_PROC_APRV_S_C ,S2.IMPRV_PROC_APRV_S_C as PROC_APRV_S_CODE ,CASE WHEN TO_CHAR(S2.IMPRV_VALT_JONGHAP_GD) IS NULL THEN '미결정' ELSE TO_CHAR(S2.IMPRV_VALT_JONGHAP_GD)||'등급' END AS IMPRV_GD /*개선역량평가*/ ,S1.IMPRV_V_C AS IMPRV_V_C /*개선분류*/ ,S1.IMPRV_G_C AS IMPRV_G_C /*개선구분*/ ,(SELECT CD_NM FROM NIC92B WHERE CD ='R021' AND CNTNT = S1.IMPRV_V_C) AS IMPRV_V ,(SELECT CD_NM FROM NIC92B WHERE CD ='R022' AND CNTNT = S1.IMPRV_G_C) AS IMPRV_G ,B.RSK_NO AS RSK_NO /*위험번호*/ ,B.REMDR_RSK_GD AS REMDR_RSK_GD /*위험등급*/ ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS HNG_BR_SWD_NM /*부서명*/ ,A.KCI_NO AS KCI_NO /*KCI번호*/ ,B.VALT_SER AS VALT_SER /*평가일련번호*/ ,B.VALT_TRN AS VALT_TRN /*평가회차*/ ,A.MNG_BRNO AS MNG_BRNO /*점번호*/ ,S2.CHG_DT AS CHG_DT /*변경일자*/ ,S2.CHG_TIME AS CHG_TIME /*변경시간*/ ,S2.CHG_OP_JKW_NO AS CHG_OP_JKW_NO /*변경직원번호*/ ,A.KCI_GJDT /*KCI기준일자*/ ,C.IMPRV_JINHG_S_C AS IMPRV_JINHG_S_C ,S2.ATTCH_FILE_NO FROM RBA_TRSK_KCI_VALT_D A /*통합위험KCI평가상세*/ LEFT JOIN RBA_KCI_IMPRV_P_D S1 /*KCI개선처리현황 상세*/ ON A.RSK_NO = S1.RSK_NO AND A.VALT_TRN = S1.VALT_TRN AND A.VALT_SER = S1.VALT_SER AND A.MNG_BRNO = S1.MNG_BRNO AND A.KCI_NO = S1.KCI_NO AND S1.IMPRV_PROC_HMK_C = '1' LEFT JOIN RBA_KCI_IMPRV_V_I S2 /*KCI개선역량 현황내역*/ ON A.RSK_NO = S2.RSK_NO AND A.VALT_TRN = S2.VALT_TRN AND A.VALT_SER = S2.VALT_SER AND A.MNG_BRNO = S2.MNG_BRNO AND A.KCI_NO = S2.KCI_NO ,RBA_TRSK_VALT_I B /*통합위험 평가내역*/ ,RBA_RSK_M C /*위험기본*/ ,RBA_KCI_M E /*KCI기본*/ ,RBA_TKCI_S F /*통합KCI기본*/ WHERE A.RSK_NO = B.RSK_NO AND A.VALT_SER = B.VALT_SER AND A.VALT_TRN = B.VALT_TRN AND A.MNG_BRNO = B.MNG_BRNO AND A.KCI_NO = E.KCI_NO AND A.RSK_NO = C.RSK_NO AND A.KCI_NO = F.KCI_NO AND F.MNG_BRNO='9999' AND C.GYLJ_DT IS NOT NULL AND C.USYN='1' AND A.IMPRV_K_C ='4'
AND B.VALT_JINHG_S_C='9'
AND A.MNG_BRNO !='9999'
AND B.MNG_BRNO =#{DEP_ID,jdbcType=VARCHAR}
AND B.VALT_DT BETWEEN #{GYLJ_DT1,jdbcType=VARCHAR} AND #{GYLJ_DT2,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
/*담당자*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (0,1,3,5,#{CHECK_CCD,jdbcType=VARCHAR})
/*승인자*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (2,4,6,#{CHECK_CCD,jdbcType=VARCHAR})
/*전체*/ AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END IN (0,1,2,3,4,5,6,7,#{CHECK_CCD,jdbcType=VARCHAR})
AND CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END = #{IMPRV_PROC_APRV_S_C,jdbcType=VARCHAR}
ORDER BY B.MNG_BRNO ASC, CASE WHEN S2.IMPRV_PROC_APRV_S_C IS NULL THEN '0' ELSE S2.IMPRV_PROC_APRV_S_C END ASC, B.VALT_TRN ASC, B.VALT_SER ASC, B.RSK_NO ASC

SELECT DATA_SER AS DATA_SER, DATA_TTL AS DATA_TTL, DATA_CTNT AS DATA_CTNT, DATA_G AS DATA_G2, DATA_INQR_CNT AS DATA_INQR_CNT, ATTCH_FILE_NO AS ATTCH_FILE_NO, CASE WHEN ATTCH_FILE_NO = '' THEN 'N' ELSE 'Y' END AS FILE_YN, USYN AS USYN, DR_DT AS DR_DT, DR_OP_JKW_NO AS DR_OP_JKW_NO, GET_LOGINID_NAME(DR_OP_JKW_NO) AS DR_OP_JKW_NM FROM RBA_CMM_DATA WHERE DR_DT BETWEEN #{DR_DT1,jdbcType=VARCHAR} AND #{DR_DT2,jdbcType=VARCHAR}
AND DATA_G = #{DATA_G,jdbcType=VARCHAR}
AND DATA_TTL = #{DATA_TTL,jdbcType=VARCHAR}
AND DR_OP_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}

SELECT A.MNG_BRNO AS MNG_BRNO ,FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,MAX(B.RSK_CNT) AS RSK_CNT ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD <= '1' THEN 1 ELSE 0 END),0) AS BRNO_CNT1 --저위험수 ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD > '1' AND A.REMDR_RSK_GD <= '3' THEN 1 ELSE 0 END),0) AS BRNO_CNT2 --중위험수 ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD >= '4' THEN 1 ELSE 0 END),0) AS BRNO_CNT3 --고위험수 ,MAX(B.REMDR_RSK_GD) AS REMDR_RSK_GD FROM RBA_MONITR_M A LEFT OUTER JOIN (SELECT MNG_BRNO , MAX(RSK_CNT) AS RSK_CNT -- 위험수 , MAX(BRBY_REMDR_RSK_GD) AS REMDR_RSK_GD -- 위험수 FROM RBA_MONITR_M C WHERE C.RSK_B_C = 'I' AND C.TOT_YN = 1
AND C.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND C.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
GROUP BY C.MNG_BRNO )B ON A.MNG_BRNO = B.MNG_BRNO WHERE A.RSK_B_C = 'I' AND A.TOT_YN = 0
AND A.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
GROUP BY A.MNG_BRNO

SELECT NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD <= '1' THEN 1 ELSE 0 END),0) AS BRNO_CNT1 --저위험부서수 ,NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD > '1' AND A.BRBY_REMDR_RSK_GD <= '3' THEN 1 ELSE 0 END),0) AS BRNO_CNT2 --중위험부서수 ,NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD >= '4' THEN 1 ELSE 0 END),0) AS BRNO_CNT3 --고위험부서수 FROM RBA_MONITR_M A WHERE A.RSK_B_C = 'I' AND A.TOT_YN = 1
AND A.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}

SELECT A.MNG_BRNO ,FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,MAX(B.RSK_CNT) AS RSK_CNT ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD <= '1' THEN 1 ELSE 0 END),0) AS BRNO_CNT1 --저위험수 ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD > '1' AND A.REMDR_RSK_GD <= '3' THEN 1 ELSE 0 END),0) AS BRNO_CNT2 --중위험수 ,NVL(SUM(CASE WHEN A.REMDR_RSK_GD >= '4' THEN 1 ELSE 0 END),0) AS BRNO_CNT3 --고위험수 ,MAX(B.REMDR_RSK_GD) AS REMDR_RSK_GD FROM RBA_MONITR_M A LEFT OUTER JOIN (SELECT MNG_BRNO , MAX(RSK_CNT) AS RSK_CNT -- 위험수 , MAX(BRBY_REMDR_RSK_GD) AS REMDR_RSK_GD -- 위험수 FROM RBA_MONITR_M C WHERE C.RSK_B_C = 'I' AND C.TOT_YN = 1
AND C.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND C.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
GROUP BY C.MNG_BRNO ) B ON A.MNG_BRNO = B.MNG_BRNO WHERE A.RSK_B_C = 'I' AND A.TOT_YN = 0
AND A.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
GROUP BY A.MNG_BRNO

SELECT NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD <= '1' THEN 1 ELSE 0 END),0) AS BRNO_CNT1 --저위험부서수 ,NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD > '1' AND A.BRBY_REMDR_RSK_GD <= '3' THEN 1 ELSE 0 END),0) AS BRNO_CNT2 --중위험부서수 ,NVL(SUM(CASE WHEN A.BRBY_REMDR_RSK_GD >= '4' THEN 1 ELSE 0 END),0) AS BRNO_CNT3 --고위험부서수 FROM RBA_MONITR_M A WHERE A.RSK_B_C = 'T' AND A.TOT_YN = 1
AND A.VALT_TRN = #{TRN,jdbcType=VARCHAR}
AND A.MNG_BRNO=#{MNG_BRNO,jdbcType=VARCHAR}

SELECT (SELECT CD_NM FROM NIC92B WHERE CD ='R029' AND CNTNT = A.RSK_B_C) AS RSK_B_C, A.RSK_G_C AS RSK_G_C, A.RSK_FLD_C AS RSK_FLD_C, A.RSK_BUMUN_C AS RSK_BUMUN_C, GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_G_C_NM, GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD_C_NM, GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN_C_NM, A.RSK_NM AS RSK_NM, A.RSK_NO AS RSK_NO, A.MNG_BRNO AS MNG_BRNO, FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM, B.RSK_PROC_NM AS RSK_PROC_NM, B.SUB_PROC_NM AS SUB_PROC_NM, A.DR_OP_JKW_NO AS DR_OP_JKW_NO, GET_LOGINID_NAME(A.DR_OP_JKW_NO) AS DR_OP_JKW_NM, TO_CHAR(TO_DATE(A.DR_DT,'YYYYMMDD'),'YYYY-MM-DD') AS DR_DT, A.USYN AS USYN FROM RBA_RSK_M A LEFT JOIN RBA_PROC_M B ON A.RSK_PROC_NO = B.RSK_PROC_NO WHERE 1=1
AND A.RSK_B_C = #{RSK_B_C,jdbcType=VARCHAR}
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{DEP_ID,jdbcType=VARCHAR}
AND A.DR_OP_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
AND A.USYN = #{USYN,jdbcType=VARCHAR}

SELECT A.KRI_NO AS KRI_NO, A.KRI_NM AS KRI_NM, A.RSK_G_C AS RSK_G_C, A.RSK_FLD_C AS RSK_FLD_C, A.RSK_BUMUN_C AS RSK_BUMUN_C, GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_G_C_NM, GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD_C_NM, GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN_C_NM, B.KRI_V AS KRI_V, B.VALT_PNT AS VALT_PNT, B.VALT_GD, TO_CHAR(TO_DATE(B.KRI_GJDT,'YYYYMMDD'),'YYYY-MM-DD') AS KRI_GJDT, A.KRI_CTNT AS KRI_CTNT, A.UNIT_C AS UNIT_C, GET_CODE_NAME('R011',A.UNIT_C) AS UNIT_NM FROM RBA_KRI_M A LEFT JOIN RBA_TKRI_S B ON A.KRI_NO = B.KRI_NO WHERE A.RSK_B_C='T' AND B.MNG_BRNO='9999'
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND A.KRI_NO = #{KRI_NO,jdbcType=VARCHAR}

SELECT A.KCI_NO AS KCI_NO, A.KCI_NM AS KCI_NM, A.TONGJE_G_C AS TONGJE_G_C, A.TONGJE_FLD_C AS TONGJE_FLD_C, A.TONGJE_BUMUN_C AS TONGJE_BUMUN_C, GET_RBA_RSK_NAME('TONGJE_G', A.TONGJE_G_C) AS TONGJE_G_C_NM, GET_RBA_RSK_NAME('TONGJE_F', A.TONGJE_FLD_C) AS TONGJE_FLD_C_NM, GET_RBA_RSK_NAME('TONGJE_B', A.TONGJE_BUMUN_C) AS TONGJE_BUMUN_C_NM, B.KCI_V AS KCI_V, B.VALT_PNT AS VALT_PNT, B.VALT_GD AS VALT_GD, TO_CHAR(TO_DATE(B.KCI_GJDT,'YYYYMMDD'),'YYYY-MM-DD') AS KCI_GJDT, A.KCI_CTNT AS KCI_CTNT, A.UNIT_C AS UNIT_C, GET_CODE_NAME('R011',A.UNIT_C) AS UNIT_NM FROM RBA_KCI_M A LEFT JOIN RBA_TKCI_S B ON A.KCI_NO = B.KCI_NO WHERE A.RSK_B_C='T' AND B.MNG_BRNO='9999'
AND A.TONGJE_G_C = #{TONGJE_G_C,jdbcType=VARCHAR}
AND A.TONGJE_FLD_C = #{TONGJE_FLD_C,jdbcType=VARCHAR}
AND A.TONGJE_BUMUN_C = #{TONGJE_BUMUN_C,jdbcType=VARCHAR}
AND A.KCI_NO = #{KCI_NO,jdbcType=VARCHAR}
